class Admin_Model_OrderItem extends Admin_Model_Base_OrderItem {

    /**
     * @param Doctrine_Connection|null $conn
     * @param bool $updateItemPrices
     */
    public function save(Doctrine_Connection $conn = null, bool $updateItemPrices = true) {
        parent::save($conn);

        if ($updateItemPrices)
            $this->order->updateItemPrices();
    }

    /**
     * @param $event
     */
    public function postDelete($event) {
        $order = $this->order;

        parent::postDelete($event);

        $order->updateItemPrices();
    }

    /**
     * @param int $orderID
     * @param array $cartItem
     * @return Admin_Model_OrderItem
     */
    public static function createOrderItem(int $orderID, array $cartItem, bool $api=null): Admin_Model_OrderItem {
        $orderItem = new Admin_Model_OrderItem();
        $orderItem->Order_ID = $orderID;
        $orderItem->PriceWithoutVat = $cartItem['PriceWithoutVat'];
        $orderItem->PriceWithVat = $cartItem['PriceWithVat'];
        $orderItem->Vat = $cartItem['Vat'];
        $orderItem->Product_ID = $api?$cartItem['Product_Api_ID']:$cartItem['Product_ID'];
        $orderItem->Quantity = $cartItem['Quantity'];
        $orderItem->save(null, false);

        return $orderItem;
    }

    /**
     * @param array $order
     * @return array
     */
    public static function getOrderItems(array $order): array {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_OrderItem object');
        $query->select('object.*, productImages.*, file.*, product.*, productLangs.Name as ProductName, productLangs.slug as slug');
        $query->leftJoin('object.product product');
        $query->leftJoin('product.productImages productImages WITH productImages.Main = true');
        $query->leftJoin('productImages.file file');
        $query->leftJoin('product.productLangs productLangs WITH productLangs.Language_ID = ?', $order['eshop']['Language_ID']);
        $query->addWhere('object.Order_ID = ?', $order['ID']);

        return $query->execute()->toArray();
    }

    /**
     * @param int $orderItemID
     * @return Admin_Model_OrderItem
     */
    public static function getOrderItem(int $orderItemID): Admin_Model_OrderItem {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_OrderItem object');
        $query->where('object.ID = ?', $orderItemID);

        return $query->fetchOne();
    }
}